/**
 * Analytics models for dashboard reporting.
 */

/**
 * High-level summary of platform metrics.
 */
export interface AnalyticsSummary {
  totalUsers: number;
  totalOrders: number;
  revenue: number;
  activeUsers: number;
}

/**
 * Per-user analytics data.
 */
export interface UserAnalytics {
  userId: string;
  orderCount: number;
  totalSpent: number;
  lastActive: Date;
}

/**
 * A single data point in a time-series trend.
 */
export interface TrendPoint {
  timestamp: Date;
  metric: string;
  value: number;
}

